using System;
using System.Collections.Generic;
using System.Linq;

static List<T> Filter<T>(List<T> items, Func<T, bool> predicate) =>
    items.Where(predicate).ToList();

class Program {
    static void Main() {
        var nums = new List<int> { 1, 2, 3, 4, 5, 6, 7, 8 };
        var evens = Filter(nums, n => n % 2 == 0);
        var large = Filter(nums, n => n > 5);
        Console.WriteLine(string.Join(" ", evens));
        Console.WriteLine(string.Join(" ", large));
    }
}

